/**
 * ClientLabs Plugin — Form Tracking
 *
 * Tracks form interactions:
 * - form_start: first focus on any input within a form (once per form)
 * - form_submit: form submission with metadata
 * - Auto-identify: extracts email from email fields on submit
 *
 * Uses event delegation (document-level listeners) for performance.
 */

import type { ClientLabsPlugin, PluginContext } from '../types'

function createFormsPlugin(): ClientLabsPlugin {
    const formStartTracked = new WeakSet<HTMLFormElement>()
    let focusHandler: ((e: FocusEvent) => void) | null = null
    let submitHandler: ((e: SubmitEvent) => void) | null = null

    return {
        name: 'forms',

        init(ctx: PluginContext): void {
            if (typeof document === 'undefined') return

            // form_start: first focus on any input within a form
            focusHandler = (e: FocusEvent): void => {
                const target = e.target as HTMLElement
                if (!target || !('tagName' in target)) return

                const tag = target.tagName
                if (tag !== 'INPUT' && tag !== 'TEXTAREA' && tag !== 'SELECT') return

                const form = target.closest('form')
                if (!form || formStartTracked.has(form)) return

                formStartTracked.add(form)
                ctx.track('form_start', {
                    formId: form.id || undefined,
                    formAction: form.action || undefined,
                    url: window.location.href,
                })
            }

            // form_submit + auto-identify from email fields
            submitHandler = (e: SubmitEvent): void => {
                const form = e.target as HTMLFormElement
                if (!form || form.tagName !== 'FORM') return

                // Extract email if present
                const emailInput = form.querySelector<HTMLInputElement>(
                    'input[type="email"], input[name*="email"], input[name*="correo"]'
                )

                const metadata: Record<string, unknown> = {
                    formId: form.id || undefined,
                    formAction: form.action || undefined,
                    url: window.location.href,
                }

                const email = emailInput?.value?.trim() || ''
                const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/

                if (email && emailRegex.test(email)) {
                    metadata.email = email
                    // Auto-identify with detected email
                    ctx.identify({ email })
                }

                ctx.track('form_submit', metadata)
            }

            document.addEventListener('focusin', focusHandler, { passive: true, capture: true })
            document.addEventListener('submit', submitHandler, { passive: true, capture: true })
        },

        destroy(): void {
            if (typeof document === 'undefined') return

            if (focusHandler) {
                document.removeEventListener('focusin', focusHandler, { capture: true })
                focusHandler = null
            }
            if (submitHandler) {
                document.removeEventListener('submit', submitHandler, { capture: true })
                submitHandler = null
            }
        },
    }
}

export default createFormsPlugin
